// Rack D – Batch / scheduled workload

let cpuLoad = Math.min(100, 25 + Math.random() * 55); // 25–80%
let ambient = 24 + Math.random() * 2;
let inlet = ambient + cpuLoad * 0.055;
let exhaust = inlet + 7 + Math.random() * 2;

const payload = {
  rack_id: "RackD",
  workload_type: "batch_processing",
  cpu_util: Number(cpuLoad.toFixed(2)),
  power_kw: Number((0.9 + cpuLoad * 0.014).toFixed(2)),
  ambient_temp_c: Number(ambient.toFixed(2)),
  inlet_temp_c: Number(inlet.toFixed(2)),
  exhaust_temp_c: Number(exhaust.toFixed(2)),
  fan_speed_rpm: Math.round(2400 + cpuLoad * 32),
  humidity: Number((43 + Math.random() * 6).toFixed(2))
};

msg.payload =
  "mosquitto_pub -d -q 1 " +
  "-h 192.168.29.21 -p 1883 " +
  "-t v1/devices/me/telemetry " +
  "-u d3badznaypit2z7xqg4x " +
  "-m \"" + JSON.stringify(payload).replace(/"/g, '\\"') + "\"";

return msg;
